#include <stdio.h>
#include <string.h>
int main() {
    int n;
    char s[101];
    scanf("%d", &n);
    scanf("%s", s);
    int dp[n][n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 0; i < n - 1; i++) {
        if (s[i] != s[i + 1]) {
            dp[i][i + 1] = 1;
        }
    }
    for (int len = 3; len <= n; len++) {
        for (int i = 0; i <= n - len; i++) {
            int j = i + len - 1;
            if (s[i] != s[j]) {
                dp[i][j] = dp[i + 1][j] + 1;
                if (dp[i][j] > dp[i][j - 1] + 1) {
                    dp[i][j] = dp[i][j - 1] + 1;
                }
            } else {
                dp[i][j] = dp[i + 1][j - 1];
            }
        }
    }
    printf("%d\n", dp[0][n - 1]);
    return 0;
}

